    73	  useEffect(() => {
    74	    return () => {
    75	      if (copyTimerRef.current !== null) {
    76	        window.clearTimeout(copyTimerRef.current);
    77	      }
    78	    };
    79	  }, []);
    80	
    81	  const handleCopy = async () => {
    82	    const ok = await copyTextToClipboard(text);
    83	    if (!ok) return;
    84	    setCopied(true);
    85	    if (copyTimerRef.current !== null) {
    86	      window.clearTimeout(copyTimerRef.current);
    87	    }
    88	    copyTimerRef.current = window.setTimeout(() => {
    89	      setCopied(false);
    90	      copyTimerRef.current = null;
    91	    }, 1600);
    92	  };
    93	
    94	  return (
    95	    <div className="rounded-xl border border-zinc-700 bg-zinc-950/90 overflow-hidden">
    96	      <div className="flex items-center justify-between px-3 py-2 border-b border-zinc-800 bg-zinc-900/70">
    97	        <span className="text-[11px] uppercase tracking-wide text-zinc-400">{language || 'code'}</span>
    98	        <div className="flex items-center gap-2">
    99	          <button
   100	            type="button"
   101	            onClick={handleCopy}
   102	            className="inline-flex items-center gap-1 rounded-md border border-zinc-700 px-2 py-1 text-[11px] text-zinc-200 hover:bg-zinc-800/90"
   103	            aria-label="Copiar codigo"
   104	          >
   105	            {copied ? <Check size={12} /> : <Copy size={12} />}
   106	            {copied ? 'Copiado' : 'Copiar'}
   107	          </button>
   108	          {canCollapse ? (
   109	            <button
   110	              type="button"
   111	              onClick={() => setExpanded((prev) => !prev)}
   112	              className="text-[11px] text-blue-300 hover:text-blue-200"
   113	            >
   114	              {expanded ? 'Ver menos' : `Ver mas (${lines.length - COLLAPSED_CODE_LINES} lineas)`}
   115	            </button>
   116	          ) : null}
   117	        </div>
   118	      </div>
   119	      <pre className="text-xs text-zinc-200 p-3 overflow-x-auto whitespace-pre">
   120	        <code>{shown.join('\n')}{!expanded && canCollapse ? '\n...' : ''}</code>
   121	      </pre>
   122	    </div>
   123	  );
